$("#swith_family_id").on("change",function(){
    if(this.checked) {
        $("#family_id").show(100);
    } else {
        $("#family_id").hide(100);
        $("#family_id").val("").change();
    }
});
$('input[name="type_driver"]').on('change',function(){
    calc_tariff();
    if($(this).val()==2) {
        $('select[name="driver"]').selectize()[0].selectize.destroy();
        $('select[name="driver"]').hide();
        $('select[name="driver2"]').selectize();
        $('select[name="driver2"]').selectize()[0].selectize.clear();
    } else {
        $('select[name="driver2"]').selectize()[0].selectize.destroy();
        $('select[name="driver2"]').hide();
        $('select[name="driver"]').selectize();
        $('select[name="driver"]').selectize()[0].selectize.clear();
    }
});
$('body').on('click','.close',function() {
    $('.modal').fadeOut(300);
});
$('body').on('click','.close0',function() {
    $('.modal').fadeOut(300);
});
$("body").on("click",".ajax-alert",function(){
    var order_id = $(this).data('id');
    Swal.fire({
        title:"Add Dispatcher Note",
        input:"text",
        showCancelButton:!0,
        confirmButtonText:"Submit",
        showLoaderOnConfirm:!0,
        confirmButtonColor:"#7a6fbe",
        cancelButtonColor:"#f46a6a",
        preConfirm:function(n){
            if(n==="" || n.length<2) {
                Swal.fire({
                    title:"Cancelled",
                    text:"Note can not be empty!",
                    icon:"error"
                });
            } else {
                $.post(location.href, { _token: $('input[name="_token"]').val(), order_id: order_id, dispatcher_notes: n }).done(function( data ) {
                    data=JSON.parse(data);
                    if(data.message=="OK") {
                        Swal.fire({
                            icon:"success",
                            title:"Add Dispatcher Note",
                            html:"Success added.",
                            confirmButtonColor:"#7a6fbe"
                        });
                    } else {
                        Swal.fire({
                            title:"Cancelled",
                            text:"Your imaginary file is safe :)",
                            icon:"error"
                        });
                    }
                });
            }
        },
        allowOutsideClick:!1
    });
});